val channel = Channel<Int>(capacity = Channel.RENDEZVOUS)

launch {
    channel.send(1) // suspend cho tới khi receiver sẵn sàng
    channel.close()
}

for (value in channel) {
    println(value)
}

val jobs = Channel<JobCommand>(capacity = 16)

val producer = launch {
    try {
        source.collect { jobs.send(it) }
    } finally {
        jobs.close()
    }
}

val consumer = launch {
    for (command in jobs) process(command)
}

val channel = Channel<UploadChunk>(
    capacity = 8,
    onUndeliveredElement = { chunk -> chunk.release() }
)

val queue = Channel<Task>(capacity = 32)
repeat(4) { workerId ->
    launch {
        for (task in queue) {
            runTask(workerId, task)
        }
    }
}

class CommandProcessor(
    private val scope: CoroutineScope,
    private val sender: MessageSender
) {
    private val commands = Channel<SendCommand>(capacity = 32)

    private val worker = scope.launch {
        for (command in commands) {
            sender.sendIdempotently(command)
        }
    }

    suspend fun submit(command: SendCommand) {
        commands.send(command)
    }

    fun close() {
        commands.close()
    }
}
